{"code": "import json
import re

# Read knowledge articles
file_path = locals()['var_functions.query_db:26']
with open(file_path, 'r') as f:
    knowledge_articles = json.load(f)

# Quote data
quote_items = locals()['var_functions.db:2']
max_discount = max(float(item['Discount']) for item in quote_items)
quote_total = sum(float(item['TotalPrice']) for item in quote_items)

# Policy patterns to search for
policy_patterns = {
    'max_discount': [
        r'(\d+)%.*(?:maximum|max|limit|cannot exceed|cap)',
        r'(?:maximum|max|limit|cannot exceed|cap).*(\d+)%',
        r'discount.*(?:maximum|max|limit|cannot exceed).*(\d+)%',
        r'(?:maximum|max).*discount.*(\d+)%'
    ],
    'approval_threshold': [
        r'\$(\d+(?:,\d+)*).*approval',
        r'approval.*\$(\d+(?:,\d+)*)',
        r'exceeds\s*\$(\d+(?:,\d+)*).*requires',
        r'(?:requires|needs).*approval.*\$(\d+(?:,\d+)*)'
    ]
}

violations = []

for article in knowledge_articles:
    title = article.get('title', '') or ''
    summary = article.get('summary', '') or ''
    faq = article.get('faq_answer__c', '') or ''
    content = (title + ' ' + summary + ' ' + faq).lower()

    article_id = article['id']

    # Check for maximum discount limits
    for pattern in policy_patterns['max_discount']:
        matches = re.findall(pattern, content, re.IGNORECASE)
        for match in matches:
            if isinstance(match, tuple):
                percent = int(next(m for m in match if m))
            else:
                percent = int(match)

            if max_discount > percent:
                violations.append({
                    'article_id': article_id,
                    'type': 'discount_limit',
                    'limit': percent,
                    'actual': max_discount
                })

    # Check for approval thresholds
    for pattern in policy_patterns['approval_threshold']:
        matches = re.findall(pattern, content, re.IGNORECASE)
        for match in matches:
            if isinstance(match, tuple):
                dollars = int(match[0].replace(',', '')) if match[0] else int(match[1].replace(',', ''))
            else:
                dollars = int(match.replace(',', ''))

            if quote_total > dollars:
                violations.append({
                    'article_id': article_id,
                    'type': 'approval_threshold',
                    'limit': dollars,
                    'actual': quote_total
                })

# Also check the specific Volume-Based Discounts article
vol_article = locals()['var_functions.db:20'][0]
vol_content = (vol_article['title'] + ' ' + vol_article['summary'] + ' ' + vol_article['faq_answer__c']).lower()

print("Analysis complete. Found violations:", len(violations))

result = {
    'violation_count': len(violations),
    'violations': violations
}

print('__RESULT__:')
print(json.dumps(result))"}
